231	              input,
232	              resolved: true,
233	              id: groupId,
234	              name: groupId,
235	            };
236	          }
237	          if (isChannelTarget(normalized)) {
238	            return {
239	              input,
240	              resolved: false,
241	              note: "expected user target",
242	            };
