81	  accountId: string;
82	}): Promise<CoreConfig> {
83	  const resolved = resolveIrcAccount({ cfg: params.cfg, accountId: params.accountId });
84	  const existing = resolved.config.nickserv;
85	  const hasExisting = Boolean(existing?.password || existing?.passwordFile);
86	  const wants = await params.prompter.confirm({
87	    message: hasExisting ? "Update NickServ settings?" : "Configure NickServ identify/register?",
88	    initialValue: hasExisting,
89	  });
90	  if (!wants) {
91	    return params.cfg;
92	  }
93	
94	  const service = String(
95	    await params.prompter.text({
96	      message: "NickServ service nick",
97	      initialValue: existing?.service || "NickServ",
98	      validate: (value) => (String(value ?? "").trim() ? undefined : "Required"),
99	    }),
100	  ).trim();
101	
102	  const useEnvPassword =
103	    params.accountId === DEFAULT_ACCOUNT_ID &&
104	    Boolean(process.env.IRC_NICKSERV_PASSWORD?.trim()) &&
105	    !(existing?.password || existing?.passwordFile)
106	      ? await params.prompter.confirm({
107	          message: "IRC_NICKSERV_PASSWORD detected. Use env var?",
108	          initialValue: true,
109	        })
110	      : false;
111	
112	  const password = useEnvPassword
113	    ? undefined
114	    : String(
115	        await params.prompter.text({
116	          message: "NickServ password (blank to disable NickServ auth)",
117	          validate: () => undefined,
118	        }),
119	      ).trim();
120	
121	  if (!password && !useEnvPassword) {
122	    return setIrcNickServ(params.cfg, params.accountId, {
123	      enabled: false,
124	      service,
125	    });
126	  }
127	
128	  const register = await params.prompter.confirm({
129	    message: "Send NickServ REGISTER on connect?",
130	    initialValue: existing?.register ?? false,
131	  });
132	  const registerEmail = register
133	    ? String(
134	        await params.prompter.text({
135	          message: "NickServ register email",
136	          initialValue:
137	            existing?.registerEmail ||
138	            (params.accountId === DEFAULT_ACCOUNT_ID
139	              ? process.env.IRC_NICKSERV_REGISTER_EMAIL
140	              : undefined),
141	          validate: (value) => (String(value ?? "").trim() ? undefined : "Required"),
142	        }),
143	      ).trim()
144	    : undefined;
145	
146	  return setIrcNickServ(params.cfg, params.accountId, {
147	    enabled: true,
148	    service,
149	    ...(password ? { password } : {}),
150	    register,
151	    ...(registerEmail ? { registerEmail } : {}),
152	  });
153	}
