6	export type ParsedIrcLine = {
7	  raw: string;
8	  prefix?: string;
9	  command: string;
10	  params: string[];
11	  trailing?: string;
12	};
13	
14	export type ParsedIrcPrefix = {
15	  nick?: string;
16	  user?: string;
17	  host?: string;
18	  server?: string;
19	};
20	
21	export function parseIrcLine(line: string): ParsedIrcLine | null {
22	  const raw = line.replace(/[\r\n]+/g, "").trim();
23	  if (!raw) {
24	    return null;
25	  }
26	
27	  let cursor = raw;
28	  let prefix: string | undefined;
29	  if (cursor.startsWith(":")) {
30	    const idx = cursor.indexOf(" ");
31	    if (idx <= 1) {
32	      return null;
33	    }
34	    prefix = cursor.slice(1, idx);
35	    cursor = cursor.slice(idx + 1).trimStart();
36	  }
37	
38	  if (!cursor) {
39	    return null;
40	  }
41	
42	  const firstSpace = cursor.indexOf(" ");
43	  const command = (firstSpace === -1 ? cursor : cursor.slice(0, firstSpace)).trim();
44	  if (!command) {
45	    return null;
46	  }
47	
48	  cursor = firstSpace === -1 ? "" : cursor.slice(firstSpace + 1);
49	  const params: string[] = [];
50	  let trailing: string | undefined;
51	
52	  while (cursor.length > 0) {
53	    cursor = cursor.trimStart();
54	    if (!cursor) {
55	      break;
56	    }
57	    if (cursor.startsWith(":")) {
58	      trailing = cursor.slice(1);
59	      break;
60	    }
61	    const spaceIdx = cursor.indexOf(" ");
62	    if (spaceIdx === -1) {
63	      params.push(cursor);
64	      break;
65	    }
66	    params.push(cursor.slice(0, spaceIdx));
67	    cursor = cursor.slice(spaceIdx + 1);
68	  }
69	
70	  return {
71	    raw,
72	    prefix,
73	    command: command.toUpperCase(),
74	    params,
75	    trailing,
76	  };
77	}
78	
79	export function parseIrcPrefix(prefix?: string): ParsedIrcPrefix {
80	  if (!prefix) {
81	    return {};
82	  }
83	  const nickPart = prefix.match(/^([^!@]+)!([^@]+)@(.+)$/);
84	  if (nickPart) {
85	    return {
86	      nick: nickPart[1],
87	      user: nickPart[2],
88	      host: nickPart[3],
89	    };
90	  }
91	  const nickHostPart = prefix.match(/^([^@]+)@(.+)$/);
92	  if (nickHostPart) {
93	    return {
94	      nick: nickHostPart[1],
95	      host: nickHostPart[2],
96	    };
97	  }
98	  if (prefix.includes("!")) {
99	    const [nick, user] = prefix.split("!", 2);
100	    return { nick, user };
101	  }
102	  if (prefix.includes(".")) {
103	    return { server: prefix };
104	  }
105	  return { nick: prefix };
106	}
107	
108	function decodeLiteralEscapes(input: string): string {
109	  // Defensive: this is not a full JS string unescaper.
110	  // It's just enough to catch common "\r\n" / "\u0001" style payloads.
111	  return input
112	    .replace(/\\r/g, "\r")
113	    .replace(/\\n/g, "\n")
114	    .replace(/\\t/g, "\t")
115	    .replace(/\\0/g, "\0")
116	    .replace(/\\x([0-9a-fA-F]{2})/g, (_, hex) => String.fromCharCode(Number.parseInt(hex, 16)))
117	    .replace(/\\u([0-9a-fA-F]{4})/g, (_, hex) => String.fromCharCode(Number.parseInt(hex, 16)));
118	}
119	
120	export function sanitizeIrcOutboundText(text: string): string {
121	  const decoded = decodeLiteralEscapes(text);
122	  return stripIrcControlChars(decoded.replace(/\r?\n/g, " ")).trim();
123	}
124	
125	export function sanitizeIrcTarget(raw: string): string {
126	  const decoded = decodeLiteralEscapes(raw);
127	  if (!decoded) {
128	    throw new Error("IRC target is required");
129	  }
130	  // Reject any surrounding whitespace instead of trimming it away.
131	  if (decoded !== decoded.trim()) {
132	    throw new Error(`Invalid IRC target: ${raw}`);
133	  }
134	  if (hasIrcControlChars(decoded)) {
135	    throw new Error(`Invalid IRC target: ${raw}`);
136	  }
137	  if (!IRC_TARGET_PATTERN.test(decoded)) {
138	    throw new Error(`Invalid IRC target: ${raw}`);
139	  }
140	  return decoded;
141	}
142	
143	export function splitIrcText(text: string, maxChars = 350): string[] {
144	  const cleaned = sanitizeIrcOutboundText(text);
145	  if (!cleaned) {
146	    return [];
147	  }
148	  if (cleaned.length <= maxChars) {
149	    return [cleaned];
150	  }
151	  const chunks: string[] = [];
152	  let remaining = cleaned;
153	  while (remaining.length > maxChars) {
154	    let splitAt = remaining.lastIndexOf(" ", maxChars);
155	    if (splitAt < Math.floor(maxChars * 0.5)) {
156	      splitAt = maxChars;
157	    }
158	    chunks.push(remaining.slice(0, splitAt).trim());
159	    remaining = remaining.slice(splitAt).trimStart();
160	  }
161	  if (remaining) {
162	    chunks.push(remaining);
163	  }
164	  return chunks.filter(Boolean);
165	}
166	
167	export function makeIrcMessageId() {
168	  return randomUUID();
169	}
