83	export function countOutboundMedia(payload: { mediaUrls?: string[]; mediaUrl?: string }): number {
84	  return resolveOutboundMediaUrls(payload).length;
85	}
86	
87	/** Check whether an outbound payload includes any media after normalization. */
88	export function hasOutboundMedia(payload: { mediaUrls?: string[]; mediaUrl?: string }): boolean {
89	  return countOutboundMedia(payload) > 0;
90	}
