276	/** Detect numeric-looking target ids for channels that distinguish ids from handles. */
277	export function isNumericTargetId(raw: string): boolean {
278	  const trimmed = raw.trim();
279	  if (!trimmed) {
280	    return false;
281	  }
282	  return /^\d{3,}$/.test(trimmed);
283	}
284	
285	/** Append attachment links to plain text when the channel cannot send media inline. */
286	export function formatTextWithAttachmentLinks(
287	  text: string | undefined,
288	  mediaUrls: string[],
289	): string {
290	  const trimmedText = text?.trim() ?? "";
291	  if (!trimmedText && mediaUrls.length === 0) {
292	    return "";
293	  }
294	  const mediaBlock = mediaUrls.length
295	    ? mediaUrls.map((url) => `Attachment: ${url}`).join("\n")
296	    : "";
297	  if (!trimmedText) {
298	    return mediaBlock;
299	  }
300	  if (!mediaBlock) {
301	    return trimmedText;
302	  }
303	  return `${trimmedText}\n\n${mediaBlock}`;
304	}
305	
306	/** Send a caption with only the first media item, mirroring caption-limited channel transports. */
307	export async function sendMediaWithLeadingCaption(params: {
308	  mediaUrls: string[];
309	  caption: string;
310	  send: (payload: { mediaUrl: string; caption?: string }) => Promise<void>;
311	  onError?: (params: {
312	    error: unknown;
313	    mediaUrl: string;
314	    caption?: string;
315	    index: number;
316	    isFirst: boolean;
317	  }) => Promise<void> | void;
318	}): Promise<boolean> {
319	  if (params.mediaUrls.length === 0) {
320	    return false;
321	  }
322	
323	  for (const [index, mediaUrl] of params.mediaUrls.entries()) {
324	    const isFirst = index === 0;
325	    const caption = isFirst ? params.caption : undefined;
326	    try {
327	      await params.send({ mediaUrl, caption });
328	    } catch (error) {
329	      if (params.onError) {
330	        await params.onError({
331	          error,
332	          mediaUrl,
333	          caption,
334	          index,
335	          isFirst,
336	        });
337	        continue;
338	      }
339	      throw error;
340	    }
341	  }
342	  return true;
343	}
344	
345	export async function deliverTextOrMediaReply(params: {
346	  payload: OutboundReplyPayload;
347	  text: string;
348	  chunkText?: (text: string) => readonly string[];
349	  sendText: (text: string) => Promise<void>;
350	  sendMedia: (payload: { mediaUrl: string; caption?: string }) => Promise<void>;
351	  onMediaError?: (params: {
352	    error: unknown;
353	    mediaUrl: string;
354	    caption?: string;
355	    index: number;
356	    isFirst: boolean;
357	  }) => Promise<void> | void;
358	}): Promise<"empty" | "text" | "media"> {
359	  const { mediaUrls } = resolveSendableOutboundReplyParts(params.payload, {
360	    text: params.text,
361	  });
362	  const sentMedia = await sendMediaWithLeadingCaption({
363	    mediaUrls,
364	    caption: params.text,
365	    send: params.sendMedia,
366	    onError: params.onMediaError,
367	  });
368	  if (sentMedia) {
369	    return "media";
370	  }
371	  if (!params.text) {
372	    return "empty";
373	  }
374	  const chunks = params.chunkText ? params.chunkText(params.text) : [params.text];
375	  let sentText = false;
376	  for (const chunk of chunks) {
377	    if (!chunk) {
378	      continue;
379	    }
380	    await params.sendText(chunk);
381	    sentText = true;
382	  }
383	  return sentText ? "text" : "empty";
384	}
385	
386	export async function deliverFormattedTextWithAttachments(params: {
387	  payload: OutboundReplyPayload;
388	  send: (params: { text: string; replyToId?: string }) => Promise<void>;
389	}): Promise<boolean> {
390	  const text = formatTextWithAttachmentLinks(
391	    params.payload.text,
392	    resolveOutboundMediaUrls(params.payload),
393	  );
394	  if (!text) {
395	    return false;
396	  }
397	  await params.send({
398	    text,
399	    replyToId: params.payload.replyToId,
400	  });
401	  return true;
402	}
