21	/** Resolve an account by id, then fall back to the default account when the primary lacks credentials. */
22	export function resolveAccountWithDefaultFallback<TAccount>(params: {
23	  accountId?: string | null;
24	  normalizeAccountId: (accountId?: string | null) => string;
25	  resolvePrimary: (accountId: string) => TAccount;
26	  hasCredential: (account: TAccount) => boolean;
27	  resolveDefaultAccountId: () => string;
28	}): TAccount {
29	  const hasExplicitAccountId = Boolean(params.accountId?.trim());
30	  const normalizedAccountId = params.normalizeAccountId(params.accountId);
31	  const primary = params.resolvePrimary(normalizedAccountId);
32	  if (hasExplicitAccountId || params.hasCredential(primary)) {
33	    return primary;
34	  }
35	
36	  const fallbackId = params.resolveDefaultAccountId();
37	  if (fallbackId === normalizedAccountId) {
38	    return primary;
39	  }
40	  const fallback = params.resolvePrimary(fallbackId);
41	  if (!params.hasCredential(fallback)) {
42	    return primary;
43	  }
44	  return fallback;
45	}
