48	export function listConfiguredAccountIds(params: {
49	  accounts: Record<string, unknown> | undefined;
50	  normalizeAccountId: (accountId: string) => string;
51	}): string[] {
52	  if (!params.accounts) {
53	    return [];
54	  }
55	  const ids = new Set<string>();
56	  for (const key of Object.keys(params.accounts)) {
57	    if (!key) {
58	      continue;
59	    }
60	    ids.add(params.normalizeAccountId(key));
61	  }
62	  return [...ids];
63	}
