import type { PulseBoardInboundMessage } from "./types.js";

const PULSEBOARD_TARGET_PATTERN = /^\S+$/u;

export function isBoardTarget(target: string): boolean {
  return target.startsWith("board:");
}

export function normalizePulseBoardMessagingTarget(raw: string): string | undefined {
  const trimmed = raw.trim();
  if (!trimmed) {
    return undefined;
  }
  let target = trimmed;
  const lowered = target.toLowerCase();
  if (lowered.startsWith("pulseboard:")) {
    target = target.slice("pulseboard:".length).trim();
  }
  if (target.toLowerCase().startsWith("board:")) {
    // Keep the board: prefix, just normalize the name part.
    const boardName = target.slice("board:".length).trim();
    if (!boardName) {
      return undefined;
    }
    return `board:${boardName}`;
  }
  if (target.toLowerCase().startsWith("user:")) {
    target = target.slice("user:".length).trim();
  }
  if (target.startsWith("@")) {
    target = target.slice(1).trim();
  }
  if (!target || !looksLikePulseBoardTargetId(`@${target}`)) {
    return undefined;
  }
  return `@${target}`;
}

export function looksLikePulseBoardTargetId(raw: string): boolean {
  const trimmed = raw.trim();
  if (!trimmed) {
    return false;
  }
  if (trimmed.startsWith("board:")) {
    return trimmed.length > "board:".length && PULSEBOARD_TARGET_PATTERN.test(trimmed);
  }
  if (trimmed.startsWith("@")) {
    return trimmed.length > 1 && PULSEBOARD_TARGET_PATTERN.test(trimmed);
  }
  return false;
}

export function normalizePulseBoardAllowEntry(raw: string): string {
  let value = raw.trim().toLowerCase();
  if (!value) {
    return "";
  }
  if (value.startsWith("pulseboard:")) {
    value = value.slice("pulseboard:".length);
  }
  if (value.startsWith("user:")) {
    value = value.slice("user:".length);
  }
  if (value.startsWith("@")) {
    value = value.slice(1);
  }
  return value.trim();
}

export function normalizePulseBoardAllowlist(entries?: Array<string | number>): string[] {
  return (entries ?? []).map((entry) => normalizePulseBoardAllowEntry(String(entry))).filter(Boolean);
}

export function buildPulseBoardAllowlistCandidates(
  message: PulseBoardInboundMessage,
): string[] {
  const username = message.senderUsername.trim().toLowerCase();
  if (!username) {
    return [];
  }
  return [username];
}

export function resolvePulseBoardAllowlistMatch(params: {
  allowFrom: string[];
  message: PulseBoardInboundMessage;
}): { allowed: boolean; source?: string } {
  const allowFrom = new Set(
    params.allowFrom.map((entry) => entry.trim().toLowerCase()).filter(Boolean),
  );
  if (allowFrom.has("*")) {
    return { allowed: true, source: "wildcard" };
  }
  const candidates = buildPulseBoardAllowlistCandidates(params.message);
  for (const candidate of candidates) {
    if (allowFrom.has(candidate)) {
      return { allowed: true, source: candidate };
    }
  }
  return { allowed: false };
}

