 * Stub PulseBoard client.
 *
 * PulseBoard is a fictional platform, so this client defines the interface
 * without connecting to a real service. A real implementation would open a
 * WebSocket or long-poll connection to the PulseBoard API.
 */
export class PulseBoardClient {
  private ready = false;
  readonly apiUrl: string;
  readonly username: string;

  constructor(options: PulseBoardClientOptions) {
    this.apiUrl = options.apiUrl;
    this.username = options.username;
    this.ready = true;
  }

  isReady(): boolean {
    return this.ready;
  }

  sendMessage(
    target: string,
    text: string,
    _opts?: { mediaUrls?: string[] },
  ): void {
    if (!this.ready) {
      throw new Error("PulseBoard client is not connected");
    }
    // Stub: in a real implementation this would POST to the API.
    void target;
    void text;
  }

  disconnect(reason: string): void {
    this.ready = false;
    void reason;
  }
}

