    abortSignal: opts.abortSignal,
    onError: (error) => {
      logger.error(`[${account.accountId}] PulseBoard error: ${error.message}`);
    },
    onMessage: async (event) => {
      if (!client) {
        return;
      }
      // Skip own messages.
      if (event.senderUsername.toLowerCase() === client.username.toLowerCase()) {
        return;
      }

      const inboundTarget = resolvePulseBoardInboundTarget({
        target: event.target,
        senderUsername: event.senderUsername,
