import { describe, expect, it } from "vitest";
import {
  isBoardTarget,
  normalizePulseBoardMessagingTarget,
  looksLikePulseBoardTargetId,
  normalizePulseBoardAllowEntry,
  normalizePulseBoardAllowlist,
  buildPulseBoardAllowlistCandidates,
  resolvePulseBoardAllowlistMatch,
} from "./normalize.js";

describe("isBoardTarget", () => {
  it("returns true for board: prefix", () => {
    expect(isBoardTarget("board:general")).toBe(true);
  });
  it("returns false for user targets", () => {
    expect(isBoardTarget("@alice")).toBe(false);
  });
  it("returns false for empty string", () => {
    expect(isBoardTarget("")).toBe(false);
  });
});

describe("normalizePulseBoardMessagingTarget", () => {
  it("normalizes board targets", () => {
    expect(normalizePulseBoardMessagingTarget("board:general")).toBe("board:general");
  });
  it("normalizes user targets with @", () => {
    expect(normalizePulseBoardMessagingTarget("@alice")).toBe("@alice");
  });
  it("strips pulseboard: prefix for boards", () => {
    expect(normalizePulseBoardMessagingTarget("pulseboard:board:ops")).toBe("board:ops");
  });
  it("strips pulseboard: prefix for users", () => {
    expect(normalizePulseBoardMessagingTarget("pulseboard:@bob")).toBe("@bob");
  });
  it("handles user: prefix", () => {
    expect(normalizePulseBoardMessagingTarget("user:carol")).toBe("@carol");
  });
  it("handles bare username without @", () => {
    expect(normalizePulseBoardMessagingTarget("dave")).toBe("@dave");
  });
  it("returns undefined for empty string", () => {
    expect(normalizePulseBoardMessagingTarget("")).toBeUndefined();
  });
  it("returns undefined for whitespace-only", () => {
    expect(normalizePulseBoardMessagingTarget("   ")).toBeUndefined();
  });
  it("returns undefined for empty board name", () => {
    expect(normalizePulseBoardMessagingTarget("board:")).toBeUndefined();
  });
});

describe("looksLikePulseBoardTargetId", () => {
  it("accepts board targets", () => {
    expect(looksLikePulseBoardTargetId("board:general")).toBe(true);
  });
  it("accepts user targets", () => {
    expect(looksLikePulseBoardTargetId("@alice")).toBe(true);
  });
  it("rejects bare names", () => {
    expect(looksLikePulseBoardTargetId("alice")).toBe(false);
  });
  it("rejects empty string", () => {
    expect(looksLikePulseBoardTargetId("")).toBe(false);
  });
  it("rejects board: with no name", () => {
    expect(looksLikePulseBoardTargetId("board:")).toBe(false);
  });
  it("rejects @ with no username", () => {
    expect(looksLikePulseBoardTargetId("@")).toBe(false);
  });
});

describe("normalizePulseBoardAllowEntry", () => {
  it("lowercases and strips @", () => {
    expect(normalizePulseBoardAllowEntry("@Alice")).toBe("alice");
  });
  it("strips pulseboard: prefix", () => {
    expect(normalizePulseBoardAllowEntry("pulseboard:Bob")).toBe("bob");
  });
  it("strips user: prefix", () => {
    expect(normalizePulseBoardAllowEntry("user:Carol")).toBe("carol");
  });
  it("returns empty for empty input", () => {
    expect(normalizePulseBoardAllowEntry("")).toBe("");
  });
  it("passes through wildcard", () => {
    expect(normalizePulseBoardAllowEntry("*")).toBe("*");
  });
});

describe("normalizePulseBoardAllowlist", () => {
  it("normalizes and filters entries", () => {
    expect(normalizePulseBoardAllowlist(["@Alice", "", "Bob"])).toEqual(["alice", "bob"]);
  });
  it("handles undefined", () => {
    expect(normalizePulseBoardAllowlist(undefined)).toEqual([]);
  });
  it("converts numbers to strings", () => {
    expect(normalizePulseBoardAllowlist([123])).toEqual(["123"]);
  });
});

describe("buildPulseBoardAllowlistCandidates", () => {
  it("returns lowercased username", () => {
    const candidates = buildPulseBoardAllowlistCandidates({
      messageId: "1",
      target: "@alice",
      senderUsername: "Alice",
      text: "hello",
      timestamp: 1,
      isGroup: false,
    });
    expect(candidates).toEqual(["alice"]);
  });
  it("returns empty for blank sender", () => {
    const candidates = buildPulseBoardAllowlistCandidates({
      messageId: "1",
      target: "@",
      senderUsername: "",
      text: "hello",
      timestamp: 1,
      isGroup: false,
    });
    expect(candidates).toEqual([]);
  });
});

describe("resolvePulseBoardAllowlistMatch", () => {
  const makeMessage = (senderUsername: string) => ({
    messageId: "1",
    target: `@${senderUsername}`,
    senderUsername,
    text: "hello",
    timestamp: 1,
    isGroup: false,
  });

  it("allows wildcard", () => {
    const result = resolvePulseBoardAllowlistMatch({
      allowFrom: ["*"],
      message: makeMessage("alice"),
    });
    expect(result.allowed).toBe(true);
    expect(result.source).toBe("wildcard");
  });
  it("allows exact match", () => {
    const result = resolvePulseBoardAllowlistMatch({
      allowFrom: ["alice"],
      message: makeMessage("Alice"),
    });
    expect(result.allowed).toBe(true);
  });
  it("rejects non-matching sender", () => {
    const result = resolvePulseBoardAllowlistMatch({
      allowFrom: ["bob"],
      message: makeMessage("alice"),
    });
    expect(result.allowed).toBe(false);
  });
  it("rejects empty allowlist", () => {
    const result = resolvePulseBoardAllowlistMatch({
      allowFrom: [],
      message: makeMessage("alice"),
    });
    expect(result.allowed).toBe(false);
  });
});

