import { describe, expect, it } from "vitest";
import {
  listPulseBoardAccountIds,
  resolveDefaultPulseBoardAccountId,
  resolvePulseBoardAccount,
} from "./accounts.js";
import type { CoreConfig } from "./types.js";

function makeConfig(overrides?: Partial<CoreConfig>): CoreConfig {
  return {
    channels: {
      pulseboard: {
        apiUrl: "https://pulseboard.example.com/api",
        apiToken: "test-token-123",
        username: "openclaw-bot",
        ...overrides?.channels?.pulseboard,
      },
    },
    ...overrides,
  } as CoreConfig;
}

describe("listPulseBoardAccountIds", () => {
  it("returns default when no accounts", () => {
    const cfg = makeConfig();
    const ids = listPulseBoardAccountIds(cfg);
    expect(ids).toContain("default");
  });
  it("includes named accounts", () => {
    const cfg = makeConfig({
      channels: {
        pulseboard: {
          accounts: {
            staging: { apiUrl: "https://staging.example.com/api" },
          },
        },
      },
    } as Partial<CoreConfig>);
    const ids = listPulseBoardAccountIds(cfg);
    expect(ids).toContain("staging");
  });
});

describe("resolveDefaultPulseBoardAccountId", () => {
  it("returns default when no defaultAccount", () => {
    const cfg = makeConfig();
    expect(resolveDefaultPulseBoardAccountId(cfg)).toBe("default");
  });
  it("returns configured defaultAccount", () => {
    const cfg = makeConfig({
      channels: {
        pulseboard: {
          defaultAccount: "staging",
          accounts: { staging: { apiUrl: "https://staging.example.com/api" } },
        },
      },
    } as Partial<CoreConfig>);
    expect(resolveDefaultPulseBoardAccountId(cfg)).toBe("staging");
  });
});

describe("resolvePulseBoardAccount", () => {
  it("resolves configured account", () => {
    const cfg = makeConfig();
    const account = resolvePulseBoardAccount({ cfg });
    expect(account.configured).toBe(true);
    expect(account.apiUrl).toBe("https://pulseboard.example.com/api");
    expect(account.username).toBe("openclaw-bot");
    expect(account.tokenSource).toBe("config");
  });

  it("marks as unconfigured when apiUrl is missing", () => {
    const cfg = makeConfig({
      channels: {
        pulseboard: {
          apiToken: "token",
          username: "bot",
        },
      },
    } as Partial<CoreConfig>);
    const account = resolvePulseBoardAccount({ cfg });
    expect(account.configured).toBe(false);
    expect(account.apiUrl).toBe("");
  });

  it("marks as unconfigured when token is missing", () => {
    const cfg = makeConfig({
      channels: {
        pulseboard: {
          apiUrl: "https://pulseboard.example.com/api",
          username: "bot",
        },
      },
    } as Partial<CoreConfig>);
    const account = resolvePulseBoardAccount({ cfg });
    expect(account.configured).toBe(false);
    expect(account.tokenSource).toBe("none");
  });

  it("resolves named account", () => {
    const cfg = makeConfig({
      channels: {
        pulseboard: {
          apiUrl: "https://default.example.com/api",
          apiToken: "default-token",
          username: "default-bot",
          accounts: {
            staging: {
              apiUrl: "https://staging.example.com/api",
              apiToken: "staging-token",
              username: "staging-bot",
            },
          },
        },
      },
    } as Partial<CoreConfig>);
    const account = resolvePulseBoardAccount({ cfg, accountId: "staging" });
    expect(account.accountId).toBe("staging");
    expect(account.apiUrl).toBe("https://staging.example.com/api");
    expect(account.username).toBe("staging-bot");
  });

  it("respects enabled flag", () => {
    const cfg = makeConfig({
      channels: {
        pulseboard: {
          enabled: false,
          apiUrl: "https://pulseboard.example.com/api",
          apiToken: "test-token",
          username: "bot",
        },
      },
    } as Partial<CoreConfig>);
    const account = resolvePulseBoardAccount({ cfg });
