import { describe, expect, it } from "vitest";
import { PulseBoardConfigSchema } from "./config-schema.js";

describe("PulseBoardConfigSchema", () => {
  it("accepts minimal valid config", () => {
    const result = PulseBoardConfigSchema.safeParse({});
    expect(result.success).toBe(true);
  });

  it("accepts full config", () => {
    const result = PulseBoardConfigSchema.safeParse({
      name: "production",
      enabled: true,
      apiUrl: "https://pulseboard.example.com/api",
      apiToken: "test-token",
      username: "openclaw-bot",
      dmPolicy: "pairing",
      allowFrom: ["alice", "bob"],
      groupPolicy: "allowlist",
      boards: {
        "board:general": { requireMention: true },
        "board:ops": { requireMention: false, tools: "enabled" },
      },
      joinBoards: ["board:general"],
    });
    expect(result.success).toBe(true);
  });

  it("accepts numeric allowFrom entries", () => {
    const result = PulseBoardConfigSchema.safeParse({
      allowFrom: [123, "alice"],
    });
    expect(result.success).toBe(true);
  });

  it("rejects open policy without wildcard allowFrom", () => {
    const result = PulseBoardConfigSchema.safeParse({
      dmPolicy: "open",
      allowFrom: ["alice"],
    });
    expect(result.success).toBe(false);
  });

  it("accepts open policy with wildcard allowFrom", () => {
    const result = PulseBoardConfigSchema.safeParse({
      dmPolicy: "open",
      allowFrom: ["*"],
    });
    expect(result.success).toBe(true);
  });

  it("accepts config with accounts", () => {
    const result = PulseBoardConfigSchema.safeParse({
      accounts: {
        staging: {
          apiUrl: "https://staging.example.com/api",
          username: "staging-bot",
        },
      },
      defaultAccount: "staging",
    });
    expect(result.success).toBe(true);
  });

  it("rejects unknown fields", () => {
    const result = PulseBoardConfigSchema.safeParse({
      unknownField: true,
    });
    expect(result.success).toBe(false);
  });
});

