import { describe, expect, it } from "vitest";
import {
  resolvePulseBoardGroupMatch,
  resolvePulseBoardGroupAccessGate,
  resolvePulseBoardRequireMention,
  resolvePulseBoardMentionGate,
  resolvePulseBoardGroupSenderAllowed,
} from "./policy.js";

describe("resolvePulseBoardGroupMatch", () => {
  it("matches direct board entry", () => {
    const match = resolvePulseBoardGroupMatch({
      boards: { "board:general": { requireMention: false } },
      target: "board:general",
    });
    expect(match.groupConfig).toBeDefined();
    expect(match.groupConfig?.requireMention).toBe(false);
  });

  it("matches case-insensitively", () => {
    const match = resolvePulseBoardGroupMatch({
      boards: { "board:General": { requireMention: true } },
      target: "board:general",
    });
    expect(match.groupConfig).toBeDefined();
  });

  it("resolves wildcard config", () => {
    const match = resolvePulseBoardGroupMatch({
      boards: { "*": { requireMention: false } },
      target: "board:unknown",
    });
    expect(match.groupConfig).toBeUndefined();
    expect(match.wildcardConfig?.requireMention).toBe(false);
  });

  it("returns empty when no boards configured", () => {
    const match = resolvePulseBoardGroupMatch({
      boards: undefined,
      target: "board:general",
    });
    expect(match.groupConfig).toBeUndefined();
    expect(match.wildcardConfig).toBeUndefined();
  });
});

describe("resolvePulseBoardGroupAccessGate", () => {
  it("blocks when disabled", () => {
    const result = resolvePulseBoardGroupAccessGate({
      groupPolicy: "disabled",
      groupMatch: {},
    });
    expect(result.allowed).toBe(false);
  });

  it("allows when open", () => {
    const result = resolvePulseBoardGroupAccessGate({
      groupPolicy: "open",
      groupMatch: {},
    });
    expect(result.allowed).toBe(true);
  });

  it("allows allowlist with matching board", () => {
    const result = resolvePulseBoardGroupAccessGate({
      groupPolicy: "allowlist",
      groupMatch: { groupConfig: {} },
    });
    expect(result.allowed).toBe(true);
  });

  it("blocks allowlist without matching board", () => {
    const result = resolvePulseBoardGroupAccessGate({
      groupPolicy: "allowlist",
      groupMatch: {},
    });
    expect(result.allowed).toBe(false);
  });

  it("allows allowlist with wildcard", () => {
    const result = resolvePulseBoardGroupAccessGate({
      groupPolicy: "allowlist",
      groupMatch: { wildcardConfig: {} },
    });
    expect(result.allowed).toBe(true);
  });
});

describe("resolvePulseBoardRequireMention", () => {
  it("defaults to true", () => {
    expect(resolvePulseBoardRequireMention({})).toBe(true);
  });

  it("uses groupConfig value", () => {
    expect(
      resolvePulseBoardRequireMention({
        groupConfig: { requireMention: false },
      }),
    ).toBe(false);
  });

  it("falls back to wildcardConfig", () => {
    expect(
      resolvePulseBoardRequireMention({
        wildcardConfig: { requireMention: false },
      }),
    ).toBe(false);
  });

  it("prefers groupConfig over wildcardConfig", () => {
    expect(
      resolvePulseBoardRequireMention({
        groupConfig: { requireMention: true },
        wildcardConfig: { requireMention: false },
      }),
    ).toBe(true);
  });
});

describe("resolvePulseBoardMentionGate", () => {
  it("skips when DM (not group)", () => {
    const result = resolvePulseBoardMentionGate({
      isGroup: false,
      requireMention: true,
      wasMentioned: false,
      hasControlCommand: false,
      allowTextCommands: false,
      commandAuthorized: false,
    });
    expect(result.shouldSkip).toBe(false);
  });

  it("does not skip when mentioned", () => {
    const result = resolvePulseBoardMentionGate({
      isGroup: true,
      requireMention: true,
      wasMentioned: true,
      hasControlCommand: false,
      allowTextCommands: false,
      commandAuthorized: false,
    });
    expect(result.shouldSkip).toBe(false);
  });

  it("skips when mention required but not mentioned", () => {
    const result = resolvePulseBoardMentionGate({
      isGroup: true,
      requireMention: true,
      wasMentioned: false,
      hasControlCommand: false,
      allowTextCommands: false,
      commandAuthorized: false,
    });
    expect(result.shouldSkip).toBe(true);
  });

  it("does not skip for authorized control command", () => {
    const result = resolvePulseBoardMentionGate({
      isGroup: true,
      requireMention: true,
      wasMentioned: false,
      hasControlCommand: true,
      allowTextCommands: true,
      commandAuthorized: true,
    });
    expect(result.shouldSkip).toBe(false);
  });
});

describe("resolvePulseBoardGroupSenderAllowed", () => {
  const makeMessage = (senderUsername: string) => ({
    messageId: "1",
    target: "board:general",
    senderUsername,
    text: "hello",
    timestamp: 1,
    isGroup: true,
  });

  it("allows all when open", () => {
    expect(
      resolvePulseBoardGroupSenderAllowed({
        groupPolicy: "open",
        message: makeMessage("alice"),
        outerAllowFrom: [],
        innerAllowFrom: [],
      }),
    ).toBe(true);
  });

  it("allows matching inner allowlist", () => {
    expect(
      resolvePulseBoardGroupSenderAllowed({
        groupPolicy: "allowlist",
        message: makeMessage("alice"),
        outerAllowFrom: [],
        innerAllowFrom: ["alice"],
      }),
    ).toBe(true);
  });

  it("falls back to outer allowlist", () => {
    expect(
      resolvePulseBoardGroupSenderAllowed({
        groupPolicy: "allowlist",
        message: makeMessage("alice"),
        outerAllowFrom: ["alice"],
        innerAllowFrom: [],
      }),
    ).toBe(true);
  });

  it("blocks non-matching sender", () => {
    expect(
      resolvePulseBoardGroupSenderAllowed({
        groupPolicy: "allowlist",
        message: makeMessage("alice"),
        outerAllowFrom: [],
        innerAllowFrom: ["bob"],
      }),
    ).toBe(false);
  });
});

