import { describe, expect, it } from "vitest";
import { probePulseBoard } from "./probe.js";
import type { CoreConfig } from "./types.js";

function makeConfig(overrides?: Partial<CoreConfig["channels"]>): CoreConfig {
  return {
    channels: {
      pulseboard: {
        apiUrl: "https://pulseboard.example.com/api",
        apiToken: "test-token-123",
        username: "openclaw-bot",
        ...overrides?.pulseboard,
      },
    },
  } as CoreConfig;
}

describe("probePulseBoard", () => {
  it("returns ok for configured account", async () => {
    const cfg = makeConfig();
    const result = await probePulseBoard(cfg);
    expect(result.ok).toBe(true);
    expect(result.apiUrl).toBe("https://pulseboard.example.com/api");
    expect(result.username).toBe("openclaw-bot");
    expect(typeof result.latencyMs).toBe("number");
  });

  it("returns error for unconfigured account", async () => {
    const cfg = makeConfig({ pulseboard: { username: "bot" } });
    const result = await probePulseBoard(cfg);
    expect(result.ok).toBe(false);
    expect(result.error).toBe("missing apiUrl, apiToken, or username");
  });

  it("returns error when apiToken is missing", async () => {
    const cfg = makeConfig({
      pulseboard: {
        apiUrl: "https://pulseboard.example.com/api",
        username: "bot",
      },
    });
    const result = await probePulseBoard(cfg);
    expect(result.ok).toBe(false);
  });
});

